var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"심도 레벨 <color=#ffd34c>불명</color> \\n<color=#ffd34c>클리포트 게임</color> 진행중","JPN":"深度レベル<color=#ffd34c>不明</color>\\n<color=#ffd34c>クリフォトゲーム</color>進行中","ENG":"[[","TWN":"深度級別<color=#ffd34c>不明</color>\\n<color=#ffd34c>逆卡巴拉遊戲</color>進行中","SCN":"深度级别<color=#ffd34c>不明</color>\\n<color=#ffd34c>神圣战役</color>进行中","DEU":"[[","FRA":"[["},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"좋아. 지금부터 진짜 마왕의 힘이 무엇인지……","JPN":"よかろう。今から真の魔王の力とはなんたるものか……","ENG":"All right. I'll show you the power of the true Demon Lord...","TWN":"很好，你們這些小丫頭，我就讓你們見識一下……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"격의 차이를 알려주마. 애송이들아.","JPN":"格の違いを思い知らせてやろうではないか。ガキども。","ENG":"Witness the difference in my power, punks.","TWN":"真正魔王的厲害，感受看看能力的落差！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>어째서?</color>","JPN":"<color=#ff3636>どうして？</color>","ENG":"<color=#ff3636>How...?</color>","TWN":"<color=#ff3636>為什麼？</color>"},"stage":{"bg":"MS_906","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>어째서야……?</color>","JPN":"<color=#ff3636>どうしてなの……？</color>","ENG":"<color=#ff3636>How can this be...?</color>","TWN":"<color=#ff3636>為什麼……？</color>"},"stage":{"bg":"MS_906","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"힘을 개방한 것만으로도 공간이 증발하기 시작했네요.","JPN":"力を解放しただけで、空間が消滅しはじめましたね。","ENG":"The space around us is evaporating, just from unleashing her powers.","TWN":"只是釋放力量，空間就開始蒸發了呢。"},"stage":{"bg":"MS_906","slots":{"L":null,"C":null,"R":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"정말이지…. 경이로운 출력이에요.","JPN":"本当に……なんと驚異的な出力でしょう。","ENG":"What magnificent power, if I do say so myself...","TWN":"的確……是令人驚歎的輸出。"},"stage":{"bg":"MS_906","slots":{"L":null,"C":null,"R":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"아, 아아아……!","JPN":"あ、あああ……！","ENG":"Ah, aaaah...!","TWN":"啊，啊啊啊……！"},"stage":{"bg":"MS_906","slots":{"L":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"저 열기다……. 평생을 갈구해 온 극상의 고통……!","JPN":"あの熱気よ……今までずっとあれほど求め続けてきた極上の苦しみ……！","ENG":"It's the heat... The ultimate pain I've been craving for, all these years...!","TWN":"那股熱情……是我一生渴求的終極痛苦……！"},"stage":{"bg":"MS_906","slots":{"L":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"어서, 어서 나에게 그 고통을 느끼게 해 다오.","JPN":"早く、早く私に苦しみを味わわせておくれ。","ENG":"Hurry, let me feel the pain.","TWN":"給我！快，快點讓我感受那種痛苦！"},"stage":{"bg":"MS_906","slots":{"L":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"오감이 망가지고 신경의 말단이 타들어가기 전에……! 자아, 어서……!","JPN":"五感が機能しなくなり、神経の末端まで燃え落ちる前に……！　さぁ、早く……！","ENG":"Before my senses die and my nerves burn to ashes...! Quickly, now...!","TWN":"在我五感壞掉，神經末端燃燒之前……！來，快點……！"},"stage":{"bg":"MS_906","slots":{"L":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>어째서, 우리가 희생해야 하는 거야?</color>","JPN":"<color=#ff3636>どうして、我々が犠牲になるの？</color>","ENG":"<color=#ff3636>Why must we be sacrificed?</color>","TWN":"<color=#ff3636>為什麼，我們要犧牲？</color>"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_INK_2","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>어째서 우리들이 잿더미가 되어야만 하는 거야?</color>","JPN":"<color=#ff3636>どうして我々が灰になるの？</color>","ENG":"<color=#ff3636>Why must we become ash?</color>","TWN":"<color=#ff3636>為什麼，我們要化為灰燼？</color>"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_INK_2","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>어머니?</color>","JPN":"<color=#ff3636>お母さん？</color>","ENG":"<color=#ff3636>Mother?</color>","TWN":"<color=#ff3636>母親？</color>"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_INK_2","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"아무것도 느껴지지 않아. 허리가 잘렸는데…… 어째서……","JPN":"何も感じない。腰を切断されたというのに……どうしてなの……","ENG":"My waist has been severed... But I don't feel a thing... Why...?","TWN":"我的腰，被砍斷了？……為什麼……我什麼都感覺不到？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"아아, 어째서……! 어째서어어……!!","JPN":"ああっ、どうしてっ……！　どうしてぇぇ……！！","ENG":"Aaah, why...! Why...!","TWN":"啊啊，為什麼……！為什麼……！！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"호오, 재미있는 반응인걸.","JPN":"ほお、面白い反応じゃのう。","ENG":"Oh, a rather interesting response.","TWN":"喔？這個反應有點意思。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"네 연약한 몸뚱아리 따위가 고통을 느낄 겨를이 있을 줄 알았느냐?","JPN":"其方のその軟弱な身体が痛みを感じる余裕なぞ、あると思ったか？","ENG":"Did you think your weak fragile body was durable enough to feel the pain?","TWN":"就憑你那副孱弱的軀體，還有閒工夫去感受什麼痛苦？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"뭐라……!","JPN":"なにっ……！","ENG":"What...!","TWN":"什麼……！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"모르는 모양이니 내가 친절함이라는 걸 발휘해서 설명해 주마.","JPN":"知らないようじゃから、親切心から教えてやろう。","ENG":"Since you have no idea where this is getting at, I shall kindly explain.","TWN":"看你好像不太明白，那我就親切地為你解釋一下。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"자고로 고통이란 건, 공격을 받고도 버틸 수 있을 때 느껴지는 거란다.","JPN":"苦痛というものはの、耐えられる攻撃に対してのみ感じるものなのじゃ。","ENG":"One can only feel pain when one's body is capable of withstanding the attack.","TWN":"自古以來，痛苦，就是在受到攻擊後還能堅持下來時才會感受到的。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"이해되느냐? 잡종 꼬마야.","JPN":"理解したか？　雑種のガキよ。","ENG":"Understood? Mongrel child.","TWN":"明白了嗎，混種的傢伙？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"안 돼……. 이래서는 안 돼…….","JPN":"ダメよ……これではダメ……","ENG":"No... This isn't how it's supposed to be...","TWN":"不，不……不應該是這樣的……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};